/**
 * @summary Update system settings (Admin only)
 */
export const getUpdateSettingsUrl = () => {
  return `/api/settings`;
};

export const updateSettings = async (
  systemSettings: SystemSettings,
  options?: RequestInit,
): Promise<SystemSettings> => {
  return customFetch<SystemSettings>(getUpdateSettingsUrl(), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(systemSettings),
  });
};

export const getUpdateSettingsMutationOptions = <
  TError = unknown,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateSettings>>,
    TError,
    { data: SystemSettings },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateSettings>>,
  TError,
  { data: SystemSettings },
  TContext
> => {
  const mutationKey = ["updateSettings"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateSettings>>,
    { data: SystemSettings }
  > = (props) => {
    const { data } = props ?? {};

    return updateSettings(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateSettingsMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateSettings>>
>;
export type UpdateSettingsMutationBody = SystemSettings;
export type UpdateSettingsMutationError = unknown;

/**
 * @summary Update system settings (Admin only)
 */
export const useUpdateSettings = <
  TError = unknown,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateSettings>>,
    TError,
    { data: SystemSettings },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updateSettings>>,
  TError,
  { data: SystemSettings },
  TContext
> => {
  return useMutation(getUpdateSettingsMutationOptions(options));
};
